import{c as t,Q as a,j as n,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses","description":"","frontmatter":{"title":"Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses","authors":"Jiahang Lin, Shichun Liu, Chengjun Pan, Lizhi Lin, Shihan Dou, Xuanjing Huang, Hang Yan, Zhenhua Han, Tao Gui","published":"2026-04-30T00:00:00.000Z","related":"research/agent-harness/references/2604.25850-ahe-observability-arxiv.md","source":"https://arxiv.org/abs/2604.25850"},"headers":[],"relativePath":"research/papers/2026-04-30-ahe-observability-driven-harness-2604-25850.md","filePath":"research/papers/2026-04-30-ahe-observability-driven-harness-2604-25850.md","lastUpdated":1779901665000}'),s={name:"research/papers/2026-04-30-ahe-observability-driven-harness-2604-25850.md"};function r(o,e,l,d,c,p){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="agentic-harness-engineering-observability-driven-automatic-evolution-of-coding-agent-harnesses" tabindex="-1">Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses <a class="header-anchor" href="#agentic-harness-engineering-observability-driven-automatic-evolution-of-coding-agent-harnesses" aria-label="Permalink to &quot;Agentic Harness Engineering: Observability-Driven Automatic Evolution of Coding-Agent Harnesses&quot;">​</a></h1><p><strong>Authors</strong>: Jiahang Lin, Shichun Liu, Chengjun Pan, Lizhi Lin, Shihan Dou, Xuanjing Huang, Hang Yan, Zhenhua Han, Tao Gui <strong>Published</strong>: April 28–30, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2604.25850" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.25850</a><strong>arXiv ID</strong>: 2604.25850 <strong>Categories</strong>: cs.SE, cs.AI <strong>Note</strong>: Full version also at <code>research/agent-harness/references/2604.25850-ahe-observability-arxiv.md</code></p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Introduces AHE (Agentic Harness Engineering), a closed-loop system for automatically evolving coding agent harnesses—the collection of tools, middleware, prompts, and memory surrounding language models. The key innovation is organizing optimization around three observability pillars: <strong>component observability</strong> (file-level harness representations), <strong>experience observability</strong> (distilled trajectory evidence), and <strong>decision observability</strong> (falsifiable edit predictions verified in subsequent rounds).</p><p>On Terminal-Bench 2, ten AHE iterations improved pass@1 from 69.7% to 77.0%, surpassing human-designed baselines. Evolved harness transfers +5.1 to +10.1 pp gains across three alternative model families.</p><hr><h2 id="core-contribution" tabindex="-1">Core Contribution <a class="header-anchor" href="#core-contribution" aria-label="Permalink to &quot;Core Contribution&quot;">​</a></h2><h3 id="framework-design" tabindex="-1">Framework Design <a class="header-anchor" href="#framework-design" aria-label="Permalink to &quot;Framework Design&quot;">​</a></h3><p>AHE formalizes agent-driven harness evolution by decomposing the harness into seven explicit, editable component types:</p><ol><li>System prompt</li><li>Tools</li><li>Middleware</li><li>Skills</li><li>Sub-agents</li><li>Memory</li><li>Configurations</li></ol><p>Each edit operates at file granularity with git-level tracking and rollback capability.</p><h3 id="system-architecture" tabindex="-1">System Architecture <a class="header-anchor" href="#system-architecture" aria-label="Permalink to &quot;System Architecture&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                   AHE System                         │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ┌─────────────┐    ┌──────────────┐    ┌─────────┐  │</span></span>
<span class="line"><span>│  │  NexAU      │    │   Agent      │    │  Evolve │  │</span></span>
<span class="line"><span>│  │  Substrate  │←───│  Debugger    │───→│  Agent  │  │</span></span>
<span class="line"><span>│  │             │    │              │    │         │  │</span></span>
<span class="line"><span>│  │ (harness as │    │ (trajectory  │    │(evidence│  │</span></span>
<span class="line"><span>│  │   files)    │    │  → evidence) │    │  edits) │  │</span></span>
<span class="line"><span>│  └─────────────┘    └──────────────┘    └─────────┘  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>NexAU substrate</strong>: Decoupled harness framework exposing components as files</p><p><strong>Agent Debugger</strong>: Transforms millions of trajectory tokens into layered, drill-down evidence corpus</p><p><strong>Evolve Agent</strong>: Makes evidence-driven edits paired with predictions, verified against next-round task outcomes</p><hr><h2 id="three-observability-pillars" tabindex="-1">Three Observability Pillars <a class="header-anchor" href="#three-observability-pillars" aria-label="Permalink to &quot;Three Observability Pillars&quot;">​</a></h2><h3 id="_1-component-observability" tabindex="-1">1. Component Observability <a class="header-anchor" href="#_1-component-observability" aria-label="Permalink to &quot;1. Component Observability&quot;">​</a></h3><ul><li>Tracks each harness component (tool call, prompt template, routing rule) at file granularity</li><li>Distinguishes &quot;component defect&quot; vs &quot;component interaction effects&quot; (non-additivity)</li><li>Identifies which component is the improvement bottleneck</li><li>Git-level tracking enables rollback when modifications regress</li></ul><h3 id="_2-experience-observability" tabindex="-1">2. Experience Observability <a class="header-anchor" href="#_2-experience-observability" aria-label="Permalink to &quot;2. Experience Observability&quot;">​</a></h3><ul><li>Structures agent execution history as semantic traces (not raw logs)</li><li>Each iteration&#39;s learning starts from &quot;which experiences caused failures&quot;</li><li>Agent Debugger compresses millions of trajectory tokens into drill-down evidence corpus</li><li>Systematic postmortem analog: structured failure attribution by component</li></ul><h3 id="_3-decision-observability" tabindex="-1">3. Decision Observability <a class="header-anchor" href="#_3-decision-observability" aria-label="Permalink to &quot;3. Decision Observability&quot;">​</a></h3><ul><li>Tracks agent decisions at branch points</li><li>Distinguishes &quot;wrong model decision&quot; from &quot;wrong harness guidance&quot;</li><li>Evolve Agent pairs each edit with a falsifiable prediction</li><li>Predictions verified against next-round task outcomes (accountability loop)</li></ul><p><strong>Attribution reliability findings:</strong></p><ul><li>Fix precision: <strong>33.7%</strong> (5× above random baseline)</li><li>Regression precision: <strong>11.8%</strong> (only 2× above random)</li></ul><p>The system reliably identifies where edits help but struggles to foresee regressions—identified as the clearest direction for future work.</p><hr><h2 id="algorithm-1-ahe-evolution-round" tabindex="-1">Algorithm 1: AHE Evolution Round <a class="header-anchor" href="#algorithm-1-ahe-evolution-round" aria-label="Permalink to &quot;Algorithm 1: AHE Evolution Round&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input: harness ℋ, task set T, budget K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>For each round r = 1 to K:</span></span>
<span class="line"><span>    1. Generate k≥2 rollouts per task</span></span>
<span class="line"><span>    2. Clean trajectory data</span></span>
<span class="line"><span>    3. Attribute prior manifest entries; revert ineffective edits</span></span>
<span class="line"><span>    4. Distill evidence into structured reports (Agent Debugger)</span></span>
<span class="line"><span>    5. Edit harness components based on evidence (Evolve Agent)</span></span>
<span class="line"><span>    6. Commit changes with manifest entries (predictions included)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Return: evolved harness ℋ^(K)</span></span></code></pre></div><hr><h2 id="empirical-results" tabindex="-1">Empirical Results <a class="header-anchor" href="#empirical-results" aria-label="Permalink to &quot;Empirical Results&quot;">​</a></h2><h3 id="terminal-bench-2-performance" tabindex="-1">Terminal-Bench 2 Performance <a class="header-anchor" href="#terminal-bench-2-performance" aria-label="Permalink to &quot;Terminal-Bench 2 Performance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>System</th><th>Pass@1</th><th>Notes</th></tr></thead><tbody><tr><td>Seed harness</td><td>69.7%</td><td>Starting point</td></tr><tr><td>Codex-CLI (human baseline)</td><td>71.9%</td><td>Human-engineered</td></tr><tr><td>ACE (automated baseline)</td><td>~70.1%</td><td>Alternative auto</td></tr><tr><td>TF-GRPO (automated baseline)</td><td>~70.8%</td><td>Alternative auto</td></tr><tr><td><strong>AHE (10 iterations)</strong></td><td><strong>77.0%</strong></td><td><strong>+7.3pp over seed</strong></td></tr></tbody></table><h3 id="component-ablation-analysis" tabindex="-1">Component Ablation Analysis <a class="header-anchor" href="#component-ablation-analysis" aria-label="Permalink to &quot;Component Ablation Analysis&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Single-component gain</th><th>Notes</th></tr></thead><tbody><tr><td>Memory</td><td>+5.6 pp</td><td>Handles boundary cases</td></tr><tr><td>Tools</td><td>+3.3 pp</td><td>Encodes verification patterns</td></tr><tr><td>Middleware</td><td>+2.2 pp</td><td>Adds closure checks</td></tr><tr><td>System prompt alone</td><td>−2.3 pp</td><td>Regresses without other components</td></tr></tbody></table><p>Sum of single-component gains: +11.1 pp Full AHE gain: +7.3 pp → Components interact <strong>non-additively</strong>; interference on long-horizon tasks.</p><h3 id="cross-domain-transfer" tabindex="-1">Cross-Domain Transfer <a class="header-anchor" href="#cross-domain-transfer" aria-label="Permalink to &quot;Cross-Domain Transfer&quot;">​</a></h3><p><strong>Task Transfer (SWE-bench-verified)</strong>:</p><ul><li>AHE achieved highest aggregate success: <strong>75.6%</strong></li><li>12–32% token consumption reduction vs baselines that regressed below seed harness</li></ul><p><strong>Model Transfer (five alternate base models)</strong>:</p><table tabindex="0"><thead><tr><th>Model</th><th>Gain</th></tr></thead><tbody><tr><td>DeepSeek-v4-flash</td><td>+10.1 pp</td></tr><tr><td>Qwen-3.6-plus</td><td>+6.3 pp</td></tr><tr><td>Gemini-3.1-flash-lite</td><td>+5.1 pp</td></tr><tr><td>GPT-5.4 variants</td><td>+2.3 to +7.3 pp</td></tr></tbody></table><p>Larger gains on less-saturated models → evolved components encode <strong>general coordination patterns</strong>, not model-family-specific tuning.</p><hr><h2 id="key-insight-observability-as-engineering-enabler" tabindex="-1">Key Insight: Observability as Engineering Enabler <a class="header-anchor" href="#key-insight-observability-as-engineering-enabler" aria-label="Permalink to &quot;Key Insight: Observability as Engineering Enabler&quot;">​</a></h2><blockquote><p>&quot;Observability is not just logging — it is structured semantic tracing that enables systematic harness improvement. Without observability, harness engineering is artisanal; with it, it becomes engineering.&quot; (2604.25850)</p></blockquote><p>This positions observability-driven evolution as <strong>complementary to model training</strong>—an externalized surface where coding-agent experience accumulates across iterations.</p><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ol><li><strong>Benchmark scope</strong>: Evaluation limited to Terminal-Bench 2 and SWE-bench-verified; broader languages and deployment contexts untested</li><li><strong>Operating point coupling</strong>: Step budgets and timeouts fitted to GPT-5.4 high during evolution; cross-model transfer conflates harness portability with operating-point dependencies</li><li><strong>Governance</strong>: AHE provides controlled workspace boundaries and versioned attribution but lacks complete safeguards for long-horizon autonomy</li></ol><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>AHE Concept</th><th>cc-workspace Current State</th><th>Gap</th></tr></thead><tbody><tr><td>Component observability</td><td><code>healthcheck.sh</code> component validation</td><td>⚠️ Static validation, not execution trace</td></tr><tr><td>Experience observability</td><td><code>research/ablations/</code> + session retros</td><td>⚠️ Manual, not automated</td></tr><tr><td>Decision observability</td><td><code>/deep-review</code> decision review</td><td>⚠️ Post-session review, not real-time</td></tr><tr><td>Automatic evolution loop</td><td>Manual Ratchet (Known Gotchas → rule)</td><td>❌ No automation</td></tr><tr><td>Git-level rollback</td><td><code>git revert</code> (manual)</td><td>⚠️ Not integrated with harness edits</td></tr></tbody></table><p><strong>Gap summary</strong>: cc-workspace observability mechanisms are all manual. AHE provides the automation path but requires significant infrastructure investment.</p><p><strong>Related research</strong>: <code>2604.21003</code> (Meta-Evolution), <code>2604.14228</code> (Claude Code Design Space)</p>`,56)])])}const u=t(s,[["render",r]]);export{g as __pageData,u as default};
